package de.fred4jupiter.fredbet.web;

import de.fred4jupiter.fredbet.domain.Group;
import de.fred4jupiter.fredbet.match.MatchService;
import org.springframework.stereotype.Component;

import java.util.*;

@Component
public class GroupAvailabilityUtil {

    private final MatchService matchService;

    public GroupAvailabilityUtil(MatchService matchService) {
        this.matchService = matchService;
    }

    public boolean isGroupAvailable(String groupName) {
        return isGroupAvailable(Group.valueOf(groupName));
    }

    private boolean isGroupAvailable(Group group) {
        return matchService.availableGroups().contains(group);
    }

    public List<Group> getGroups() {
        Set<Group> groups = matchService.availableGroups();
        if (groups.isEmpty()) {
            return Collections.emptyList();
        }
        return groups.stream().filter(Objects::nonNull).sorted(Comparator.comparing(Group::ordinal)).toList();
    }

    public boolean isDividerNecessary(Group group) {
        if (group == null) {
            return false;
        }

        final Set<Group> groups = matchService.availableGroups();
        if (groups.contains(Group.ROUND_OF_THIRTY_TWO) && Group.ROUND_OF_THIRTY_TWO.equals(group)) {
            return true;
        } else if (!groups.contains(Group.ROUND_OF_THIRTY_TWO) && Group.ROUND_OF_SIXTEEN.equals(group)) {
            return true;
        }

        return List.of(Group.FINAL, Group.GAME_FOR_THIRD, Group.GROUP_A).contains(group);
    }
}

package org.hswebframework.web.cache.supports;

import com.google.common.cache.Cache;
import lombok.AllArgsConstructor;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

import java.util.Arrays;

@SuppressWarnings("all")
@AllArgsConstructor
public class GuavaReactiveCache<E> extends AbstractReactiveCache<E> {

    private Cache<Object, Object> cache;


    @Override
    public Mono<Void> evictAll(Iterable<?> key) {
        return Mono.fromRunnable(() -> cache.invalidateAll(key));
    }

    @Override
    protected Mono<Object> getNow(Object key) {
        return Mono.justOrEmpty(cache.getIfPresent(key));
    }

    @Override
    public Mono<Void> putNow(Object key, Object value) {
        cache.put(key, value);
        return Mono.empty();
    }

    @Override
    public Mono<Void> evict(Object key) {
        return Mono.fromRunnable(() -> cache.invalidate(key));
    }

    @Override
    public Flux<E> getAll(Object... keys) {
        return Flux.<E>defer(() -> {
            if (keys == null || keys.length == 0) {
                return Flux
                        .fromIterable(cache.asMap().values())
                        .map(e -> (E) e);
            }
            return Flux.fromIterable(cache.getAllPresent(Arrays.asList(keys)).values())
                       .map(e -> (E) e);
        });
    }


    @Override
    public Mono<Void> clear() {
        return Mono.fromRunnable(() -> cache.invalidateAll());
    }
}

package org.hswebframework.web.bean;

import com.alibaba.fastjson.JSON;
import com.google.common.collect.Sets;
import lombok.AllArgsConstructor;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.util.*;

@Getter
@Setter
@AllArgsConstructor
@NoArgsConstructor
public class Diff {

    private String property;

    private Object before;

    private Object after;


    public static List<Diff> of(Object before, Object after, String... ignoreProperty) {
        List<Diff> diffs = new ArrayList<>();
        Set<String> ignores = Sets.newHashSet(ignoreProperty);

        Map<String, Object> beforeMap = FastBeanCopier.copy(before, HashMap::new);
        Map<String, Object> afterMap = FastBeanCopier.copy(after, HashMap::new);

        for (Map.Entry<String, Object> entry : afterMap.entrySet()) {
            if (ignores.contains(entry.getKey())) {
                continue;
            }
            Object afterValue = entry.getValue();
            String key = entry.getKey();
            Object beforeValue = beforeMap.get(key);
            if (!CompareUtils.compare(beforeValue, afterValue)) {
                diffs.add(new Diff(key, beforeValue, afterValue));
            }
        }
        return diffs;

    }

    @Override
    public String toString() {
        return JSON.toJSONString(this);
    }
}

package com.netflix.appinfo.providers;

import com.netflix.archaius.api.Config;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.inject.Inject;
import javax.inject.Singleton;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

@Singleton
public class Archaius2VipAddressResolver implements VipAddressResolver {

    private static final Logger logger = LoggerFactory.getLogger(Archaius2VipAddressResolver.class);

    private static final Pattern VIP_ATTRIBUTES_PATTERN = Pattern.compile("\\$\\{(.*?)\\}");

    private final Config config;

    @Inject
    public Archaius2VipAddressResolver(Config config) {
        this.config = config;
    }

    @Override
    public String resolveDeploymentContextBasedVipAddresses(String vipAddressMacro) {
        if (vipAddressMacro == null) {
            return null;
        }

        String result = vipAddressMacro;

        Matcher matcher = VIP_ATTRIBUTES_PATTERN.matcher(result);
        while (matcher.find()) {
            String key = matcher.group(1);
            String value = config.getString(key, "");

            logger.debug("att:{}", matcher.group());
            logger.debug(", att key:{}", key);
            logger.debug(", att value:{}", value);
            logger.debug("");
            result = result.replaceAll("\\$\\{" + key + "\\}", value);
            matcher = VIP_ATTRIBUTES_PATTERN.matcher(result);
        }

        return result;
    }
}

