package org.hswebframework.web.crud.configuration;

import org.hswebframework.ezorm.rdb.mapping.parser.EntityTableMetadataParser;
import org.hswebframework.ezorm.rdb.metadata.RDBColumnMetadata;
import org.hswebframework.ezorm.rdb.metadata.RDBTableMetadata;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicReference;

public class CompositeEntityTableMetadataResolver implements EntityTableMetadataResolver {

    private final List<EntityTableMetadataParser> resolvers = new ArrayList<>();

    private final Map<Class<?>, AtomicReference<RDBTableMetadata>> cache = new ConcurrentHashMap<>();

    public void addParser(EntityTableMetadataParser resolver) {
        resolvers.add(resolver);
    }

    @Override
    public RDBTableMetadata resolve(Class<?> entityClass) {

        return cache.computeIfAbsent(entityClass, type -> new AtomicReference<>(doResolve(type))).get();
    }

    private RDBTableMetadata doResolve(Class<?> entityClass) {
        return resolvers
            .stream()
                .map(resolver -> resolver.parseTableMetadata(entityClass))
                .filter(Optional::isPresent)
                .map(Optional::get)
                .reduce((t1, t2) -> {
                    t2.merge(t1);
                    return t2;
                }).orElse(null);
    }
}

package org.jobrunr.jobs.mappers;

import org.jobrunr.jobs.Job;
import org.slf4j.MDC;

import java.util.Map;
import java.util.stream.Collectors;

public class MDCMapper {

    public static final String JOBRUNR_MDC_KEY = "mdc";
    public static final String JOBRUNR_MDC_JOB_ID_KEY = "jobrunr.jobId";
    public static final String JOBRUNR_MDC_JOB_NAME_KEY = "jobrunr.jobName";
    public static final String JOBRUNR_MDC_JOB_SIGNATURE_KEY = "jobrunr.jobSignature";

    private MDCMapper() {
        // private constructor for SonarQube
    }

    public static void saveMDCContextToJob(Job job) {
        Map<String, String> mdcContext = MDC.getCopyOfContextMap();
        if (mdcContext == null) return;
        mdcContext.forEach((key, value) -> {
            if (value != null) {
                job.getMetadata().put(JOBRUNR_MDC_KEY + "-" + key, value);
            }
        });
    }

    public static void loadMDCContextFromJob(Job job) {
        Map<String, Object> jobMetadata = job.getMetadata();
        Map<String, String> mdcContextMap = jobMetadata.entrySet().stream()
                .filter(entry -> entry.getKey().startsWith(JOBRUNR_MDC_KEY + "-"))
                .collect(Collectors.toMap(entry -> entry.getKey().substring(4), entry -> entry.getValue().toString()));
        mdcContextMap.put(JOBRUNR_MDC_JOB_ID_KEY, job.getId().toString());
        mdcContextMap.put(JOBRUNR_MDC_JOB_NAME_KEY, job.getJobName());
        mdcContextMap.put(JOBRUNR_MDC_JOB_SIGNATURE_KEY, job.getJobSignature());
        MDC.setContextMap(mdcContextMap);
    }

}

package com.alibaba.otter.canal.admin.common;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.net.URL;
import java.nio.charset.StandardCharsets;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class TemplateConfigLoader {

    private static final Logger logger              = LoggerFactory.getLogger(TemplateConfigLoader.class);

    public static final String  CONF_DIR            = "conf";
    public static final String  CANAL_CONFIG_TMP    = "canal-template.properties";
    public static final String  INSTANCE_CONFIG_TMP = "instance-template.properties";

    public static String loadCanalConfig() {
        return loadFile(CANAL_CONFIG_TMP);
    }

    public static String loadInstanceConfig() {
        return loadFile(INSTANCE_CONFIG_TMP);
    }

    private static String loadFile(String fileName) {
        File configFile = new File(".." + File.separator + CONF_DIR + File.separator + fileName);
        if (!configFile.exists()) {
            URL url = TemplateConfigLoader.class.getClassLoader().getResource("");
            if (url != null) {
                configFile = new File(url.getPath() + fileName + File.separator);
            }
        }
        if (!configFile.exists()) {
            return null;
        }
        try (InputStream in = new FileInputStream(configFile)) {
            byte[] bytes = new byte[in.available()];
            in.read(bytes);
            return new String(bytes, StandardCharsets.UTF_8);
        } catch (IOException e) {
            logger.error("Read " + fileName + " error", e);
        }

        return null;
    }
}

package de.fred4jupiter.fredbet.util;

import ch.qos.logback.classic.Level;
import de.fred4jupiter.fredbet.Application;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

@Component
public class LoggingUtil implements LogLevelChangable {

    private static final String APP_PACKAGE_LOGGER = Application.class.getPackageName();

    private static final Logger LOG = LoggerFactory.getLogger(LoggingUtil.class);

    @Override
    public void setLogLevelTo(LogLevel logLevel) {
        LOG.info("Setting log level to {}", logLevel);
        getAppPackageLogger().setLevel(toLevel(logLevel));
    }

    @Override
    public LogLevel getCurrentLogLevel() {
        return toLogLevel(getAppPackageLogger().getLevel());
    }

    private ch.qos.logback.classic.Logger getAppPackageLogger() {
        return (ch.qos.logback.classic.Logger) LoggerFactory.getLogger(APP_PACKAGE_LOGGER);
    }

    private LogLevel toLogLevel(Level level) {
        if (Level.DEBUG.equals(level)) {
            return LogLevel.DEBUG;
        } else if (Level.INFO.equals(level)) {
            return LogLevel.INFO;
        } else if (Level.WARN.equals(level)) {
            return LogLevel.WARN;
        } else if (Level.ERROR.equals(level)) {
            return LogLevel.ERROR;
        }
        return LogLevel.ERROR;
    }

    private Level toLevel(LogLevel logLevel) {
        return switch (logLevel) {
            case DEBUG -> Level.DEBUG;
            case INFO -> Level.INFO;
            case WARN -> Level.WARN;
            default -> Level.ERROR;
        };
    }
}

