package org.openmetadata.service.apps.scheduler;

import lombok.extern.slf4j.Slf4j;
import org.openmetadata.service.jdbi3.CollectionDAO;
import org.openmetadata.service.search.SearchRepository;
import org.quartz.Job;
import org.quartz.JobDetail;
import org.quartz.Scheduler;
import org.quartz.SchedulerException;
import org.quartz.simpl.SimpleJobFactory;
import org.quartz.spi.TriggerFiredBundle;

@Slf4j
public class CustomJobFactory extends SimpleJobFactory {
  private final CollectionDAO collectionDAO;
  private final SearchRepository searchRepository;

  public CustomJobFactory(CollectionDAO collectionDAO, SearchRepository searchRepository) {
    super();
    this.collectionDAO = collectionDAO;
    this.searchRepository = searchRepository;
  }

  @Override
  public Job newJob(TriggerFiredBundle bundle, Scheduler Scheduler) throws SchedulerException {
    JobDetail jobDetail = bundle.getJobDetail();
    Class<? extends Job> jobClass = jobDetail.getJobClass();

    try {
      LOG.debug("Producing instance of Job '{}', class={}", jobDetail.getKey(), jobClass.getName());

      return jobClass
          .getDeclaredConstructor(CollectionDAO.class, SearchRepository.class)
          .newInstance(collectionDAO, searchRepository);
    } catch (Exception var7) {
      throw new SchedulerException(
          "Problem instantiating class '" + jobDetail.getJobClass().getName() + "'", var7);
    }
  }
}

package org.openmetadata.service.migration.context;

import java.util.HashMap;
import java.util.List;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import org.jdbi.v3.core.Handle;
import org.openmetadata.service.migration.api.MigrationProcess;

@Slf4j
public class MigrationWorkflowContext {
  @Getter private final HashMap<String, MigrationContext> migrationContext;
  private final Handle handle;

  public MigrationWorkflowContext(Handle handle) {
    this.migrationContext = new HashMap<>();
    this.handle = handle;
  }

  public void computeInitialContext(String currentMaxMigrationVersion) {
    computeMigrationSafely(new MigrationContext(currentMaxMigrationVersion, List.of(), handle));
  }

  public void computeMigrationContext(MigrationProcess process, boolean compute) {
    MigrationContext context =
        new MigrationContext(process.getVersion(), process.getMigrationOps(), handle);
    if (compute) {
      computeMigrationSafely(context);
    } else {
      this.migrationContext.put(context.getVersion(), context);
    }
  }

  private void computeMigrationSafely(MigrationContext context) {
    try {
      context.compute();
      context.show();
      this.migrationContext.put(context.getVersion(), context);
    } catch (Exception e) {
      LOG.warn("Error computing context for [{}] due to [{}]", context.getVersion(), e);
    }
  }
}

package com.giffing.bucket4j.spring.boot.starter.core.predicates;

import com.giffing.bucket4j.spring.boot.starter.context.ExecutePredicate;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.server.PathContainer;
import org.springframework.web.util.pattern.PathPattern;
import org.springframework.web.util.pattern.PathPatternParser;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

@Slf4j
public abstract class PathExecutePredicate<T> extends ExecutePredicate<T> {

	private final PathPatternParser pathPatternParser = new PathPatternParser();

	private List<PathPattern> pathPatterns = new ArrayList<>();

	public boolean testPath(String servletPath) {
		PathContainer path = PathContainer.parsePath(servletPath);
		var matches = pathPatterns
			.stream()
			.filter(p -> p.matches(path))
			.findFirst();
		log.debug("path-predicate;path:{};value:{};result:{}", servletPath, pathPatterns, matches.isPresent());
		return matches.isPresent();
	}

	@Override
	public String name() {
		return "PATH";
	}

	@Override
	public ExecutePredicate<T> parseSimpleConfig(String simpleConfig) {
		pathPatterns = Arrays.stream(simpleConfig.split(","))
			.map(String::trim)
			.map(pathPatternParser::parse)
			.toList();
		return this;
	}

}

